class Solution {
    private Long[][] f;
    private int[] nums;
    private int n;

    public long minIncrease(int[] nums) {
        n = nums.length;
        this.nums = nums;
        f = new Long[n][2];
        return dfs(1, n & 1 ^ 1);
    }

    private long dfs(int i, int j) {
        if (i >= n - 1) {
            return 0;
        }
        if (f[i][j] != null) {
            return f[i][j];
        }
        int cost = Math.max(0, Math.max(nums[i - 1], nums[i + 1]) + 1 - nums[i]);
        long ans = cost + dfs(i + 2, j);
        if (j > 0) {
            ans = Math.min(ans, dfs(i + 1, 0));
        }
        return f[i][j] = ans;
    }
}

